/*===================================================================================================================================*/
/*  U1    u1_g_oXDoCANDtcTrchk_B1508(const U2 u2_a_ELPSD)                                                                            */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      void                                                                                                             */
/*  Return:         OXDC_DTC_TR_INA  (0x00U)  : DTC INActive                                                                         */
/*                  OXDC_DTC_TR_ACT  (0x01U)  : DTC ACTive                                                                           */
/*                  OXDC_DTC_TR_N_A  (0x02U)  : DTC Not Applicable                                                                   */
/*===================================================================================================================================*/
U1    u1_g_oXDoCANDtcTrchk_B1508(const U2 u2_a_ELPSD)
{
    U1              u1_t_trchk;

    u1_t_trchk = u1_g_ThblnkrDtcTrchk() & (U1)THBLNKR_OSC_SHORT;
    if(u1_t_trchk != (U1)0x00U){
        u1_t_trchk = (U1)OXDC_DTC_TR_ACT;
    }

    return(u1_t_trchk);
}
